BEGIN TRANSACTION;
DROP TABLE IF EXISTS "aniversariantes";
CREATE TABLE aniversariantes (
	id INTEGER NOT NULL, 
	membro_id INTEGER NOT NULL, 
	dia INTEGER NOT NULL, 
	mes INTEGER NOT NULL, 
	PRIMARY KEY (id), 
	FOREIGN KEY(membro_id) REFERENCES membros (id)
);
DROP TABLE IF EXISTS "contribuicoes_festas";
CREATE TABLE contribuicoes_festas (
	id INTEGER NOT NULL, 
	festa_id INTEGER NOT NULL, 
	membro_id INTEGER NOT NULL, 
	valor NUMERIC(10, 2) NOT NULL, 
	data_contribuicao DATE, 
	descricao VARCHAR(200), 
	PRIMARY KEY (id), 
	FOREIGN KEY(festa_id) REFERENCES festas (id), 
	FOREIGN KEY(membro_id) REFERENCES membros (id)
);
DROP TABLE IF EXISTS "despesas";
CREATE TABLE despesas (
	id INTEGER NOT NULL, 
	descricao VARCHAR(200) NOT NULL, 
	valor NUMERIC(10, 2) NOT NULL, 
	categoria VARCHAR(50), 
	data DATE NOT NULL, 
	mes INTEGER NOT NULL, 
	ano INTEGER NOT NULL, 
	PRIMARY KEY (id)
);
DROP TABLE IF EXISTS "festas";
CREATE TABLE festas (
	id INTEGER NOT NULL, 
	nome VARCHAR(100) NOT NULL, 
	data DATE NOT NULL, 
	local VARCHAR(200), 
	descricao TEXT, 
	valor_previsto NUMERIC(10, 2), 
	valor_realizado NUMERIC(10, 2), 
	PRIMARY KEY (id)
);
DROP TABLE IF EXISTS "membros";
CREATE TABLE membros (
	id VARCHAR(36) NOT NULL, 
	user_id VARCHAR(36), 
	matricula VARCHAR(50), 
	inscricao VARCHAR(50), 
	nome_completo VARCHAR(255), 
	cpf VARCHAR(20), 
	email VARCHAR(255), 
	telefone VARCHAR(30), 
	celular VARCHAR(30), 
	ddd VARCHAR(20), 
	endereco VARCHAR(255), 
	bairro VARCHAR(120), 
	cidade VARCHAR(120), 
	estado VARCHAR(50), 
	cep VARCHAR(20), 
	ect VARCHAR(50), 
	data_nascimento DATE, 
	data_associacao DATE, 
	status VARCHAR(20), 
	sexo VARCHAR(20), 
	cat VARCHAR(50), 
	beneficio VARCHAR(120), 
	observacoes TEXT, 
	created_at DATETIME, 
	updated_at DATETIME, 
	PRIMARY KEY (id)
);
DROP TABLE IF EXISTS "pagamentos";
CREATE TABLE pagamentos (
	id INTEGER NOT NULL, 
	membro_id INTEGER NOT NULL, 
	valor NUMERIC(10, 2) NOT NULL, 
	mes INTEGER NOT NULL, 
	ano INTEGER NOT NULL, 
	data_pagamento DATE, 
	forma_pagamento VARCHAR(50), 
	observacoes TEXT, 
	PRIMARY KEY (id), 
	FOREIGN KEY(membro_id) REFERENCES membros (id)
);
DROP TABLE IF EXISTS "participantes_festas";
CREATE TABLE participantes_festas (
	id INTEGER NOT NULL, 
	festa_id INTEGER NOT NULL, 
	membro_id INTEGER NOT NULL, 
	confirmado BOOLEAN, 
	data_confirmacao DATETIME, 
	PRIMARY KEY (id), 
	FOREIGN KEY(festa_id) REFERENCES festas (id), 
	FOREIGN KEY(membro_id) REFERENCES membros (id)
);
DROP TABLE IF EXISTS "usuarios";
CREATE TABLE usuarios (
	id INTEGER NOT NULL, 
	nome VARCHAR(100) NOT NULL, 
	email VARCHAR(100) NOT NULL, 
	senha VARCHAR(255) NOT NULL, 
	ativo BOOLEAN, 
	data_criacao DATETIME, 
	PRIMARY KEY (id), 
	UNIQUE (email)
);
DROP INDEX IF EXISTS "ix_membros_cidade";
CREATE INDEX ix_membros_cidade ON membros (cidade);
DROP INDEX IF EXISTS "ix_membros_matricula";
CREATE UNIQUE INDEX ix_membros_matricula ON membros (matricula);
DROP INDEX IF EXISTS "ix_membros_status";
CREATE INDEX ix_membros_status ON membros (status);
COMMIT;
